// Solution
import sys
def binary_search(arr, n, target):
    left = 0
    right = n - 1
    while left <= right:
        mid = (left + right) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            left = mid + 1
        else:
            right = mid - 1
    return -1
if __name__ == '__main__':
    arr = [-1, 0, 1, 2, 3, 4, 5]
    n = len(arr)
    target = 2
    result = binary_search(arr, n, target)
    if result != -1:
        print(result)
    else:
        print(-1)

